package com.hugogonzalez.polentracker.collector.messaging;
import com.hugogonzalez.polentracker.collector.config.MessagingConfig; import com.hugogonzalez.polentracker.collector.source.PollenSourceAdapterFactory; import com.hugogonzalez.polentracker.messaging.*; import org.springframework.amqp.rabbit.core.RabbitTemplate; import org.springframework.stereotype.Service; import java.time.Instant; import java.util.UUID;
@Service public class CollectionProcessor {private final PollenSourceAdapterFactory factory; private final RabbitTemplate rabbit; public CollectionProcessor(PollenSourceAdapterFactory f,RabbitTemplate r){factory=f;rabbit=r;}
 public void process(CollectionRequest request){var measurements=factory.get(request.sourceType()).collect(request.params()); for(var measurement:measurements){UUID eventId=UUID.randomUUID(); String key=request.sourceType()+"|"+measurement.location().latitude()+"|"+measurement.location().longitude()+"|"+measurement.pollenType()+"|"+measurement.validAt()+"|"+measurement.metricType(); rabbit.convertAndSend(MessagingConfig.EXCHANGE,"collection.measurement-collected",new PollenMeasurementCollected("1.0",eventId,request.requestId(),request.sourceType(),Instant.now(),key,measurement));} rabbit.convertAndSend(MessagingConfig.EXCHANGE,"collection.completed",new CollectionCompleted("1.0",UUID.randomUUID(),request.requestId(),measurements.size(),Instant.now()));}}
